package framework.datafile.src.org.ofbiz.datafile;

public class ModelDataFile { public static final String SEP_FIXED_LENGTH = "fixed-length" ; public static final String SEP_FIXED_RECORD = "fixed-record" ; public static final String SEP_DELIMITED = "delimited" ; public String name = "" ; public String typeCode = "" ; public String sender = "" ; public String receiver = "" ; public int recordLength = - 1 ; public char delimiter = '|' ; public String textDelimiter = null ; public String separatorStyle = "" ; public String description = "" ; public List < ModelRecord > records = new ArrayList < ModelRecord > ( ) ; public ModelRecord getModelRecord ( String recordName ) { for ( ModelRecord curRecord : records ) { if ( curRecord . name . equals ( recordName ) ) { return curRecord ; } } return null ; } public String getName ( ) { return name ; } public void setName ( String name ) { this . name = name ; } public String getTypeCode ( ) { return typeCode ; } public void setTypeCode ( String typeCode ) { this . typeCode = typeCode ; } public String getSender ( ) { return sender ; } public void setSender ( String sender ) { this . sender = sender ; } public String getReceiver ( ) { return receiver ; } public void setReceiver ( String receiver ) { this . receiver = receiver ; } public int getRecordLength ( ) { return recordLength ; } public void setRecordLength ( int recordLength ) { this . recordLength = recordLength ; } public char getDelimiter ( ) { return delimiter ; } public void setDelimiter ( char delimiter ) { this . delimiter = delimiter ; } public String getSeparatorStyle ( ) { return separatorStyle ; } public void setSeparatorStyle ( String separatorStyle ) { this . separatorStyle = separatorStyle ; } public String getDescription ( ) { return description ; } public void setDescription ( String description ) { this . description = description ; } public List < ModelRecord > getRecords ( ) { return records ; } public void setRecords ( List < ModelRecord > records ) { this . records = records ; } }